INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('32-ket-tang-3',3,32,'TỔNG KẾT TẦNG 3','Tong ket tang 3',32,'draft','2026-06-20T16:48:25Z','2026-06-20T16:48:25Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3e9f7ab4-ef97-4694-bc3c-8f7c68b27c32','32-ket-tang-3',NULL,2,'Ma Trận Phân Tách: Lớp Vận Hành Trực Sàn Và Lớp Nền Móng Kiểm Soát','ma-tran-phan-tach-lop-van-hanh-truc-san-va-lop-nen-mong-kiem-soat',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e794767e-fa2b-4806-84c0-65355f02d0b3','3e9f7ab4-ef97-4694-bc3c-8f7c68b27c32',0,'text','Khép lại các cấu phần cốt lõi của bản đồ quản trị, bức tranh toàn cảnh về một chuỗi nha khoa tăng trưởng bứt phá đã được phơi bày trọn vẹn. Trong kiến trúc tổng thể của **Dental Empire**, mọi chiến dịch truyền thông, mọi phác đồ lâm sàng hay điểm chạm trải nghiệm sảnh chờ đều không thể tồn tại độc lập. Chúng cần một bệ đỡ hạ tầng vững chắc để không bị sụp đổ khi dòng khách hàng ùa vào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('753325ab-a71a-47ae-b12e-e6c39060415e','3e9f7ab4-ef97-4694-bc3c-8f7c68b27c32',1,'text','Sự kết hợp liên thông giữa **Finance OS**, **People OS** và **Data OS** chính là lớp bê tông cốt thép, tạo nên phần nền móng tối cao giúp toàn bộ hệ thống phát triển bền vững và không thể bị phá vỡ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4e17610-17a7-4c8e-80f6-0ea1e82c895a','3e9f7ab4-ef97-4694-bc3c-8f7c68b27c32',2,'text','Một nha khoa tự vận hành được cấu trúc thành hai tầng kỹ thuật rõ rệt: Tầng giao diện (tạo ra dòng tiền ngắn hạn) và Tầng hạ tầng kiểm soát (bảo chứng sự sinh tồn dài hạn).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72dd9444-4fbd-4a5c-af90-574d40d827e3','3e9f7ab4-ef97-4694-bc3c-8f7c68b27c32',3,'image',NULL,'book/32-ket-tang-3/d979eb70-be80-4280-ab3d-4ba712a50069-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ccbe2c12-840e-4b35-b223-da9a7e444316','32-ket-tang-3',NULL,2,'Ba Câu Hỏi Tối Cao Để Kiểm Toán Lâm Sàng Tổ Chức Của Founder','ba-cau-hoi-toi-cao-e-kiem-toan-lam-sang-to-chuc-cua-founder',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c760b0d7-c10d-4b45-a90d-98597ac5ee92','ccbe2c12-840e-4b35-b223-da9a7e444316',4,'text','Nếu không có bộ ba hệ điều hành nền móng này, người chủ phòng khám sẽ mãi mãi bị kẹt trong vùng sương mù vận hành. Bộ ba OS này cung cấp 3 câu hỏi phác đồ để kiểm tra sức khỏe doanh nghiệp hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c887c96c-75a3-442b-a3ee-f3446b076ac4','ccbe2c12-840e-4b35-b223-da9a7e444316',5,'text','- **Finance OS (Màng lọc Thịnh vượng):** Trả lời câu hỏi: *Phòng khám có thực sự tạo ra lợi nhuận ròng hay không?* Hệ thống này bịt kín các lỗ rò rỉ chi phí, theo dõi sát sao công nợ trả góp chỉnh nha và giữ cho mạch máu thanh khoản luôn lưu thông an toàn.- **People OS (Màng lọc Thực thi):** Trả lời câu hỏi: *Đội ngũ có đủ năng lực vận hành bộ máy hay không?* Hệ thống này đóng gói khung năng lực, chuẩn hóa ma trận trách nhiệm SLA và giải phóng động lực tự thân của nhân sự bằng cơ chế lương thưởng 3P sòng phẳng.- **Data OS (Màng lọc Sự thật):** Trả lời câu hỏi: *Mọi quyết định chiến lược có đang dựa trên sự thật hay không?* Hệ thống này thiết lập monitor theo dõi chỉ số sinh tồn thời gian thực, đập tan trò chơi đổ lỗi liên phòng ban và buộc tất cả phải nói chuyện bằng số liệu thực chứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6dcbfe6b-ab35-433b-a46b-f696d8db0749','32-ket-tang-3',NULL,2,'Bước Nhảy Tiến Hóa: Giải Phóng Founder Và Nhân Bản Hệ Thống','buoc-nhay-tien-hoa-giai-phong-founder-va-nhan-ban-he-thong',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('853ba494-47bf-4dae-9b60-16dd73b0e722','6dcbfe6b-ab35-433b-a46b-f696d8db0749',6,'text','Khi bộ ba hệ điều hành nền móng làm tốt nhiệm vụ của mình, một bước nhảy bước ngoặt về mặt vị thế sẽ được kích hoạt bên trong cấu trúc của phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8db16355-cea7-4227-91e9-13ed9bc5b2b0','6dcbfe6b-ab35-433b-a46b-f696d8db0749',7,'text','***Dental Empire chính thức thoát xác khỏi mô hình một phòng khám vãng lai phụ thuộc hoàn toàn vào năng lực lâm sàng cá nhân hay sự có mặt giám sát thủ công của người sáng lập (Founder-Dependent). ***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15c6a7c4-64db-4716-8e9c-7a9b00d3dd83','6dcbfe6b-ab35-433b-a46b-f696d8db0749',8,'text','***Doanh nghiệp bước lên vị thế của một HỆ THỐNG TĂNG TRƯỞNG CÓ KIỂM SOÁT nơi mọi quyết định được dẫn đường bằng dữ liệu sạch, mọi quy trình được thực thi bằng một đội ngũ tinh nhuệ có năng lực tự chủ, dòng tiền ròng luôn được bảo vệ và sở hữu khả năng đóng gói để nhân bản quy mô không giới hạn.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1cd5778d-951c-40cc-be69-edf5b195032d','32-ket-tang-3',NULL,2,'Chỉ Số Sẵn Sàng Nhân Bản Mô Hình (SRI)','chi-so-san-sang-nhan-ban-mo-hinh-sri',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ee6ddfa-1c7b-47a8-b6f7-d9b9c552e779','1cd5778d-951c-40cc-be69-edf5b195032d',9,'text','Để đưa ra quyết định tối cao về việc có nên nâng số lượng ghế nha tại cơ sở hiện tại hoặc tiến hành mở chuỗi chi nhánh mới hay không, ban điều hành bắt buộc phải đối soát chỉ số **Sẵn sàng nhân bản hệ thống (System Readiness Index - ****SRI****)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f05bb48d-fcb9-440c-ac13-84a3a359552e','1cd5778d-951c-40cc-be69-edf5b195032d',10,'text','SRI (\\%) = \\left( \\frac{\\text{Điểm số chuẩn hóa đạt từ (Finance OS + People OS + Data OS)}}{\\text{Tổng điểm tiêu chuẩn tối đa của hạ tầng nền móng}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b0a624b-186a-4aed-9fae-88aa19a58411','1cd5778d-951c-40cc-be69-edf5b195032d',11,'text','- **Ngưỡng an toàn để phát lệnh mở rộng quy mô:** Chỉ số SRI bắt buộc phải đạt mức **\\ge 95\\%** duy trì liên tục trong hai quý gần nhất.- **Kỷ luật siết phanh vận hành:** Nếu chỉ số này nằm dưới ngưỡng 90% (ví dụ: dữ liệu CRM còn nhiễm rác, quỹ lương phình to vượt trần hoặc nhân sự cốt lõi biến động liên tục), chủ phòng khám **tuyệt đối không được phép mở rộng cơ sở**. Việc cố tình mở chuỗi khi nền móng lỏng lẻo sẽ ngay lập tức nhân bản sự hỗn loạn, dẫn đến nguy cơ sụp đổ dây chuyền và gãy trận thanh khoản toàn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e905d0dd-44bf-4598-a8c3-0828c77126a2','1cd5778d-951c-40cc-be69-edf5b195032d',12,'image',NULL,'book/32-ket-tang-3/0ba84ff5-27a0-4c64-83c6-38062155e574-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05568f34-46e4-45e6-b4c3-ea6bdff46b99','1cd5778d-951c-40cc-be69-edf5b195032d',13,'text','**Mantra tối cao khóa toàn bộ cẩm nang vận hành Dental Empire:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d909966-23dc-4655-ac59-6a253701e74d','1cd5778d-951c-40cc-be69-edf5b195032d',14,'text','*"Đừng xây dựng một phòng khám nha khoa chỉ để mua về cho mình một công việc bận rộn hơn dưới danh nghĩa làm chủ. Hãy dùng luật chơi sòng phẳng của Finance OS, quy trình tự chủ của People OS và sự thật thực chứng của Data OS để kiến tạo nên một hệ thống tự vận hành. Khi hệ thống mạnh hơn con người, doanh nghiệp của bạn mới thực sự chạm đến sự tự do và phát triển trường tồn."*',NULL,NULL,NULL,NULL,NULL);
